def load_tx802_presets_from_embedded_csv():
    f = StringIO(TX802_PRESET_AB_CSV)
    reader = csv.reader(f)

    rows = list(reader)
    header = rows[0]
    voces = []

    for cols in rows[1:]:
        # 列数が合わない行は壊れている
        if len(cols) != len(header):
            print("BROKEN ROW:", len(cols), "expected", len(header))
            print(cols)
            continue

        row = dict(zip(header, cols))
        voice = {}

        for k, v in row.items():
            if k in ("bank", "name"):
                voice[k] = v
            else:
                voice[k] = int(v)

        voces.append(voice)

    return voces


TX802_VOCES_AB = load_tx802_presets_from_embedded_csv()